{
  "type": "FLIP_CARD",
  "lessonText": "Understand the key differences between various data structures in Java.",
  "data": {
    "cards": [
      {
        "front": "Array",
        "back": "Fixed size, fast access. Best for indexed data.",
        "icon": "array_icon"
      },
      {
        "front": "ArrayList",
        "back": "Dynamic size, slower access than arrays. Good for resizable lists.",
        "icon": "arraylist_icon"
      },
      {
        "front": "LinkedList",
        "back": "Dynamic size, efficient insertions/deletions. Better for frequent updates.",
        "icon": "linkedlist_icon"
      },
      {
        "front": "HashMap",
        "back": "Key-value pairs, fast retrieval. Ideal for associative arrays.",
        "icon": "hashmap_icon"
      }
    ]
  }
}
